const Redis = require('ioredis');
const { randomUUID } = require('crypto');

const body = $input.first().json.body ?? {};
const patientId = $input.first().json.query?.patientId || body.patientId;
const { name, whatsappNumber, profilePhotoUrl } = body;

if (!patientId || !name || !whatsappNumber) {
  return [{ json: { success: false, error: 'patientId, name, and whatsappNumber are required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const exists = await redis.exists(`patient:${patientId}`);
  if (!exists) {
    await redis.quit();
    return [{ json: { success: false, error: 'Patient not found' } }];
  }

  const count = await redis.llen(`patient:${patientId}:contacts`);
  if (count >= 5) {
    await redis.quit();
    return [{ json: { success: false, error: 'Maximum 5 contacts allowed' } }];
  }

  const contactId = randomUUID();
  const order = count;

  await redis.hset(`contact:${contactId}`, {
    patientId,
    name,
    whatsappNumber,
    profilePhotoUrl: profilePhotoUrl || '',
    order: String(order)
  });
  await redis.rpush(`patient:${patientId}:contacts`, contactId);

  await redis.quit();
  return [{ json: { contactId, name, whatsappNumber, profilePhotoUrl: profilePhotoUrl || null, order } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
